import React, { useState } from "react";
import { Link } from "react-router-dom";
import "./Notes.css";

export default function Notes() {
  const [notes, setNotes] = useState([]);

  function handleSave(e) {
    e.preventDefault();
    const title = e.target.title.value.trim();
    const content = e.target.content.value.trim();

    if (!title || !content) {
      alert("Both fields are required!");
      return;
    }

    const newNote = { title, content };
    const updatedNotes = [...notes, newNote];
    setNotes(updatedNotes);

    localStorage.setItem("myNotes", JSON.stringify(updatedNotes));

    e.target.reset();
  }

  return (
    <div className="notes-container">
      <h2>My Notes</h2>

      <form onSubmit={handleSave}>
        <label>Title</label>
        <input name="title" type="text" placeholder="Title" required />

        <label>Content</label>
        <textarea name="content" placeholder="Write your note here..." rows="5" required></textarea>

        <button type="submit">Save Note</button>
      </form>

      {notes.length === 0 ? (
        <p>No notes yet.</p>
      ) : (
        <ul>
          {notes.map((note, index) => (
            <li key={index}><strong>{note.title}:</strong> {note.content}</li>
          ))}
        </ul>
      )}

      <h3>📚 Study Resources to Learn and Revise</h3>
      <div className="resources-grid">
        <div className="resource-card">
          <img src="https://www.w3schools.com/images/w3schools_green.jpg" alt="W3Schools" />
          <h4>🌐 W3Schools</h4>
          <p>Learn HTML, CSS, JavaScript, and more with simple tutorials.</p>
          <a href="https://www.w3schools.com/" target="_blank" rel="noreferrer">Visit</a>
        </div>
        <div className="resource-card">
          <img src="https://upload.wikimedia.org/wikipedia/commons/thumb/4/43/GeeksforGeeks.svg/1200px-GeeksforGeeks.svg.png" alt="GeeksforGeeks Logo"></img>
          <h4>💻 GeeksforGeeks</h4>
          <p>Master programming concepts, algorithms, and coding questions.</p>
          <a href="https://www.geeksforgeeks.org/" target="_blank" rel="noreferrer">Visit</a>
        </div>
        <div className="resource-card">
          <img src="https://tse4.mm.bing.net/th/id/OIP.LcXrTu6oqBs7kHzk_BeuCgAAAA?pid=Api&P=0&h=180" alt="freeCodeCamp Logo"></img>
          <h4>⚡ freeCodeCamp</h4>
          <p>Learn coding by building projects with free full-length courses.</p>
          <a href="https://www.freecodecamp.org/" target="_blank" rel="noreferrer">Visit</a>
        </div>
        <div className="resource-card">
          <h4>📖 MDN Web Docs</h4>
          <img src="https://cdn-1.webcatalog.io/catalog/mdn-web-docs/mdn-web-docs-icon-filled-256.webp?v=1714775085873" alt="MDN Logo"></img>
          <p>The best official docs for web technologies like HTML, CSS, JS.</p>
          <a href="https://developer.mozilla.org/" target="_blank" rel="noreferrer">Visit</a>
        </div>
        <div class="resource-card">
          <img src="https://cdn-1.webcatalog.io/catalog/javatpoint/javatpoint-icon-unplated.png?v=1714777503504" alt="JavaTpoint Logo"></img>
          <h3>📗 JavaTpoint</h3>
          <p>Simple explanations for Java, Python, C, C++, Web Dev topics.</p>
          <a href="https://www.javatpoint.com/" target="_blank" rel="noreferrer" class="visit-btn">Visit</a>
        </div>
        <div class="resource-card">
          <img src="https://images.crunchbase.com/image/upload/c_pad,h_256,w_256,f_auto,q_auto:eco,dpr_1/jjp8px3g1vtfyyutzbtj" alt="Programiz Logo"></img>
          <h3>📘 Programiz</h3>
          <p>Easy tutorials and examples for Python, C, C++, Java beginners.</p>
          <a href="https://www.programiz.com/" target="_blank" rel="noreferrer" class="visit-btn">Visit</a>
        </div>
      </div>

      <Link to="/dashboard" className="back-link">← Back to Dashboard</Link>
    </div>
  );
}
